module.exports = function(RED) {
    "use strict";

    function NeuralSoftmaxNode(n) {
        RED.nodes.createNode(this, n);
        var node = this;
        node._held = null;

        node.neuralRelease = function() {
            if (node._held) {
                var h = node._held;
                node._held = null;
                h.msg.payload = h.output;
                h.send(h.msg);
                h.done();
            }
        };

        node.on("input", function(msg, send, done) {
            var input = msg.payload;
            if (!Array.isArray(input)) {
                input = [input];
            }

            var max = Math.max.apply(null, input);
            var exps = input.map(function(v) { return Math.exp(v - max); });
            var sum = exps.reduce(function(a, b) { return a + b; }, 0);
            var output = exps.map(function(v) { return v / sum; });

            msg.neural = msg.neural || {};
            msg.neural.type = "softmax";
            msg.neural.shape = [output.length];
            msg.neural.step = (msg.neural.step || 0) + 1;

            if (msg.neural.hold && !node._held) {
                node._held = { output: output, msg: msg, send: send, done: done };
                node.status({ fill: "yellow", shape: "ring", text: "step " + msg.neural.step + " waiting..." });
                return;
            }

            msg.payload = output;
            var topIdx = output.indexOf(Math.max.apply(null, output));
            node.status({ fill: "blue", shape: "dot", text: "argmax: " + topIdx + " (" + output[topIdx].toFixed(3) + ")" });

            if (RED.neural) { RED.neural.outputs[node.id] = { values: output, type: "neural-softmax", name: node.name || "", timestamp: Date.now(), shape: [output.length] }; }

            send(msg);
            done();
        });
    }

    RED.nodes.registerType("neural-softmax", NeuralSoftmaxNode);
};
